def word_frequency(text):
    words = text.lower().split()
    freq = {}
    for word in words:
        word = word.strip(".,!?")
        freq[word] = freq.get(word, 0) + 1
    return dict(sorted(freq.items(), key=lambda x: x[1], reverse=True))

text = "the cat sat on the mat the cat is back"
freq = word_frequency(text)
for word, count in list(freq.items())[:5]:
    print(f"{word}: {count}")

def bmi_category(bmi):
    if bmi < 18.5:
        return "Underweight"
    elif bmi < 25:
        return "Normal weight"
    elif bmi < 30:
        return "Overweight"
    return "Obese"

def calculate_bmi(weight_kg, height_m):
    bmi = weight_kg / (height_m ** 2)
    return round(bmi, 1)

bmi = calculate_bmi(70, 1.75)
print(f"BMI: {bmi}")
print(f"Category: {bmi_category(bmi)}")

def todo_app():
    tasks = []

    def add(task):
        tasks.append(task)
        print(f"Added: {task}")

    def remove(task):
        if task in tasks:
            tasks.remove(task)
            print(f"Done: {task}")

    def show():
        for i, t in enumerate(tasks, 1):
            print(f"  {i}. {t}")

    add("Buy groceries")
    add("Learn Python")
    add("Go for a walk")
    show()
    remove("Buy groceries")
    print("Remaining:")
    show()

todo_app()

def celsius_to_fahrenheit(c):
    return (c * 9/5) + 32

def celsius_to_kelvin(c):
    return c + 273.15

def convert_from_celsius(temp):
    print(f"{temp}°C = {celsius_to_fahrenheit(temp):.1f}°F")
    print(f"{temp}°C = {celsius_to_kelvin(temp):.2f}K")

convert_from_celsius(0)
print()
convert_from_celsius(100)
